    .intel_syntax noprefix
# -----------------------------------------------------------------------------
# shell.asm - 命令行交互界面（串口终端）
# v1.60 - 1200 WASM tests milestone
# -----------------------------------------------------------------------------
    .code32

# ============================================================================
# BSS
# ============================================================================
    .section .bss
    .globl  shell_cmd_buf
shell_cmd_buf:
    .space  128
    .globl  shell_cmd_len
shell_cmd_len:
    .space  4
    .globl  shell_cursor_pos    # 当前光标在缓冲中的位置（支持左右移动）
shell_cursor_pos:
    .space  4
    .globl  shell_history_buf   # 上一条命令缓冲区 (128 字节)
shell_history_buf:
    .space  128
    .globl  shell_date_ticks    # 临时存储 tick 转秒数
shell_date_ticks:
    .space  4

# Network
ping_target_ip:
    .space  4                   # target IP for ping command

# WASM REPL buffer
wasmrepl_buf:
    .space  512                 # buffer for hex input -> WASM bytes
wasmrepl_len:
    .space  4                   # byte count in wasmrepl_buf
wasmrepl_hex_buf:
    .space  1024                # buffer for hex string input (e.g. "00 61 73 6D...")

# UDP send parameters
udp_send_dst_ip_tmp:
    .space  4
udp_send_dst_port_tmp:
    .space  2
udp_send_data_len_tmp:
    .space  4
udp_send_data_buf:
    .space  512

# PCI 扫描计数器
pciscan_bus:
    .space  4
pciscan_dev:
    .space  4
pciscan_func:
    .space  4
pciscan_count:
    .space  4

# FAT32 fatread 命令缓冲区
fat32_filename_buf:
    .space  12                  # 8.3 格式文件名 (11 bytes + null)
fat32_file_buffer:
    .space  512                 # 文件数据缓冲区

# ============================================================================
# shell_run: 主循环（串口终端）
# ============================================================================
    .section .text
    .globl  shell_run
shell_run:
    # 打印提示符（串口 + VGA）
    mov     esi, offset shell_prompt
    call    uart_puts
    mov     esi, offset shell_prompt
    call    vga_print_string_len

    # 清空命令缓冲
    xor     eax, eax
    mov     [shell_cmd_len], eax
    mov     [shell_cursor_pos], eax

1:  # 读取字符（串口输入）
    call    uart_getc

    cmp     al, 0x1B          # ESC — 可能是方向键
    je      .escape_seq
    cmp     al, 0x08          # 退格
    je      .backspace
    cmp     al, 0x7F          # 退格
    je      .backspace
    cmp     al, 0x0D          # 回车
    je      .enter
    cmp     al, 0x0A          # 换行
    je      .enter
    cmp     al, 0x03          # Ctrl+C — 关机
    je      .ctrl_c
    cmp     al, 0x20          # 可打印字符起始
    jb      1b                # 忽略控制字符
    cmp     al, 0x7E
    ja      1b

    # 普通字符: 追加到缓冲末尾
    mov     ecx, [shell_cmd_len]
    cmp     ecx, 127
    jge     1b                # 缓冲满

    # 存入缓冲区
    mov     [shell_cmd_buf + ecx], al
    inc     ecx
    mov     [shell_cmd_len], ecx
    mov     [shell_cursor_pos], ecx

    # 回显（字符仍在 al 中）
    push    eax
    call    uart_putc         # 回显到串口
    pop     eax
    push    eax
    call    vga_putchar       # 回显到VGA
    pop     eax
    jmp     1b

.escape_seq:
    # 读取 ESC [ X 序列
    call    uart_getc
    cmp     al, '['
    jne     1b                # 不是 [ 开头的 ESC 序列，忽略

    call    uart_getc
    cmp     al, 'A'           # 上箭头
    je      .arrow_up
    cmp     al, 'B'           # 下箭头
    je      .arrow_down
    cmp     al, 'C'           # 右箭头
    je      .arrow_right
    cmp     al, 'D'           # 左箭头
    je      .arrow_left
    jmp     1b                # 其他 ESC 序列，忽略

.arrow_up:
    # 从历史缓冲区恢复上一条命令
    mov     esi, offset shell_history_buf
    mov     edi, offset shell_cmd_buf
    mov     ecx, 128
    cld
    rep     movsb

    # 计算长度
    mov     esi, offset shell_cmd_buf
    call    utils_strlen
    mov     [shell_cmd_len], eax
    mov     [shell_cursor_pos], eax

    # 回显整行
    test    eax, eax
    jz      9f
    mov     esi, offset shell_cmd_buf
    mov     ecx, eax
4:  movzx   eax, byte ptr [esi]
    push    eax
    call    uart_putc
    pop     eax
    push    eax
    call    vga_putchar
    pop     eax
    inc     esi
    dec     ecx
    jnz     4b
9:  jmp     1b

.arrow_down:
    # 清空缓冲区（没有历史可前进）
    xor     eax, eax
    mov     [shell_cmd_len], eax
    mov     [shell_cursor_pos], eax
    jmp     1b

.arrow_right:
    # 光标右移
    mov     ecx, [shell_cursor_pos]
    cmp     ecx, [shell_cmd_len]
    jge     1b
    inc     dword ptr [shell_cursor_pos]
    # 串口光标右移 (ANSI)
    mov     esi, offset ansi_cursor_right
    call    uart_puts
    jmp     1b

.arrow_left:
    # 光标左移
    mov     ecx, [shell_cursor_pos]
    test    ecx, ecx
    jz      1b
    dec     dword ptr [shell_cursor_pos]
    # 串口光标左移 (ANSI)
    mov     esi, offset ansi_cursor_left
    call    uart_puts
    jmp     1b

.backspace:
    mov     ecx, [shell_cmd_len]
    test    ecx, ecx
    jz      1b                # 缓冲为空
    dec     ecx
    mov     [shell_cmd_len], ecx
    mov     [shell_cursor_pos], ecx

    # 末尾补空格（覆盖最后一个字符）
    mov     byte ptr [shell_cmd_buf + ecx], ' '

    # 回显退格序列（串口）
    mov     al, 0x08
    call    uart_putc
    mov     al, ' '
    call    uart_putc
    mov     al, 0x08
    call    uart_putc

    # VGA退格：回退光标
    mov     eax, [vga_cursor]
    test    eax, eax
    jz      1b
    dec     eax
    mov     [vga_cursor], eax
    call    vga_set_cursor_hw

    jmp     1b

.enter:
    # 终止字符串
    mov     ecx, [shell_cmd_len]
    lea     edx, [shell_cmd_buf + ecx]
    mov     byte ptr [edx], 0

    # 保存到历史缓冲区
    mov     esi, offset shell_cmd_buf
    mov     edi, offset shell_history_buf
    mov     ecx, 128
    cld
    rep     movsb

    # 打印换行（串口 + VGA）
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc
    mov     al, 0x0a
    call    vga_putchar
    mov     al, 0x0d
    call    vga_putchar

    # 分发命令
    call    shell_dispatch

    # 新提示符（串口 + VGA）
    mov     esi, offset shell_prompt
    call    uart_puts
    mov     esi, offset shell_prompt
    call    vga_print_string_len

    # 重置缓冲
    xor     eax, eax
    mov     [shell_cmd_len], eax
    mov     [shell_cursor_pos], eax

    jmp     1b

.ctrl_c:
    # 打印 "^C" 然后关机
    mov     al, '^'
    call    uart_putc
    mov     al, 'C'
    call    uart_putc
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc
    jmp     kernel_halt

# ============================================================================
# vga_print_string_len: VGA 输出指定长度字符串
# 输入: esi = 字符串指针, ecx = 长度
# （shell 内部使用，因为历史回显等场景已知长度但无 null 终止）
# ============================================================================
    .globl  vga_print_string_len
vga_print_string_len:
    push    edx
    push    ecx
    push    esi
1:  cmp     ecx, 0
    je      2f
    mov     al, [esi]
    push    eax
    call    vga_putchar
    pop     eax
    inc     esi
    dec     ecx
    jmp     1b
2:  pop     esi
    pop     ecx
    pop     edx
    ret

# ============================================================================
# shell_dispatch: 命令分发
# ============================================================================
    .globl  shell_dispatch
shell_dispatch:
    push    esi
    push    edi
    push    ecx

    mov     esi, offset shell_cmd_buf

    # "help"
    mov     edi, offset cmd_help
    call    utils_strcmp
    test    eax, eax
    jz      .do_help

    # "clear"
    mov     edi, offset cmd_clear
    call    utils_strcmp
    test    eax, eax
    jz      .do_clear

    # "version"
    mov     edi, offset cmd_version
    call    utils_strcmp
    test    eax, eax
    jz      .do_version

    # "tick"
    mov     edi, offset cmd_tick
    call    utils_strcmp
    test    eax, eax
    jz      .do_tick

    # "reboot"
    mov     edi, offset cmd_reboot
    call    utils_strcmp
    test    eax, eax
    jz      .do_reboot

    # "shutdown"
    mov     edi, offset cmd_shutdown
    call    utils_strcmp
    test    eax, eax
    jz      .do_shutdown

    # "meminfo"
    mov     edi, offset cmd_meminfo
    call    utils_strcmp
    test    eax, eax
    jz      .do_meminfo

    # "ps"
    mov     edi, offset cmd_ps
    call    utils_strcmp
