    call    utils_strcmp
    test    eax, eax
    jz      .do_wasmtest1200

    # "wasmring3" - WASM ring 3 test (enter user mode, print WASM)
    mov     edi, offset cmd_wasmring3
    call    utils_strcmp
    test    eax, eax
    jz      .do_wasmring3

    # "wasmrepl" - WASM interactive REPL
    mov     edi, offset cmd_wasmrepl
    call    utils_strcmp
    test    eax, eax
    jz      .do_wasmrepl

    # "kill <pid>" - 终止进程
    mov     edi, offset cmd_kill
    mov     ecx, 4
    call    utils_strncmp
    test    eax, eax
    jz      .do_kill

