    mov     edi, offset cmd_cat
    mov     ecx, 4
    call    utils_strncmp
    test    eax, eax
    jz      .do_cat

    # "touch <file>" - prefix match
    mov     edi, offset cmd_touch
    mov     ecx, 6
    call    utils_strncmp
    test    eax, eax
    jz      .do_touch

