    mov     ecx, 7
    call    utils_strncmp
    test    eax, eax
    jz      .do_wasmapp

    # "echo <text>" - prefix match (5 chars: "echo ")
    mov     edi, offset cmd_echo_prefix
    mov     ecx, 5
    call    utils_strncmp
    test    eax, eax
    jz      .do_echo

