    # "dhcp" - run DHCP client
    mov     edi, offset cmd_dhcp
    call    utils_strcmp
    test    eax, eax
    jz      .do_dhcp

    # "pciscan" - scan PCI devices
    mov     edi, offset cmd_pciscan
    call    utils_strcmp
    test    eax, eax
    jz      .do_pciscan

    # "ring3" - enter user mode (ring 3)
    mov     edi, offset cmd_ring3
    call    utils_strcmp
    test    eax, eax
    jz      .do_ring3

    # "diskinfo" - show disk information
    mov     edi, offset cmd_diskinfo
    call    utils_strcmp
    test    eax, eax
    jz      .do_diskinfo

    # "diskread <lba>" - read disk sector
    mov     edi, offset cmd_diskread
    mov     esi, offset shell_cmd_buf
    mov     ecx, 9               # "diskread " length
    call    utils_strncmp
    test    eax, eax
    jz      .do_diskread

    # "diskwrite <lba>" - write disk sector
    mov     edi, offset cmd_diskwrite
    mov     esi, offset shell_cmd_buf
    mov     ecx, 10              # "diskwrite " length
    call    utils_strncmp
    test    eax, eax
    jz      .do_diskwrite

    # "fatls" - list FAT32 root directory
    mov     edi, offset cmd_fatls
    call    utils_strcmp
    test    eax, eax
    jz      .do_fatls

    # "fatread <filename>" - read FAT32 file
    mov     edi, offset cmd_fatread
    mov     esi, offset shell_cmd_buf
    mov     ecx, 8                 # "fatread " length
    call    utils_strncmp
    test    eax, eax
    jz      .do_fatread

    # 未知命令
    mov     esi, offset msg_unknown
    call    uart_puts
    mov     esi, offset shell_cmd_buf
    call    utils_strlen
    push    eax
    push    esi
    call    uart_puts
    pop     esi
    pop     ecx
    # 换行
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc

    pop     ecx
    pop     edi
    pop     esi
    ret

.do_help:
    mov     esi, offset help_text
    call    uart_puts
    mov     esi, offset help_text
    call    vga_print_string_len
    pop     ecx
    pop     edi
    pop     esi
    ret

.do_clear:
    # ANSI 清屏（串口）
    mov     esi, offset ansi_clear
    call    uart_puts
    # VGA 清屏
    call    vga_clear
    pop     ecx
    pop     edi
    pop     esi
    ret

.do_version:
    mov     esi, offset version_text
    call    uart_puts
    mov     esi, offset version_text
    call    vga_print_string_len
    pop     ecx
    pop     edi
    pop     esi
    ret

.do_tick:
    call    get_tick_count
    push    eax
    mov     esi, offset tick_prefix
    call    uart_puts
    mov     esi, offset tick_prefix
    call    vga_print_string_len
    pop     eax
    lea     edi, [shell_cmd_buf]
    mov     dl, 10
    call    utils_itoa
    mov     esi, eax
    call    utils_strlen
    mov     ecx, eax
    push    esi               # 保存 buffer 指针
    call    uart_puts
    pop     esi               # 恢复 buffer 指针
    call    vga_print_string_len
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc
    pop     ecx
    pop     edi
    pop     esi
    ret

.do_reboot:
    pop     ecx
    pop     edi
    pop     esi
    jmp     kernel_reboot

.do_shutdown:
    pop     ecx
    pop     edi
    pop     esi
    jmp     kernel_halt

.do_meminfo:
    # 打印 "Memory: "
    mov     esi, offset meminfo_prefix
    call    uart_puts

    # 获取总内存（KB）
    call    get_total_memory
    push    eax
    mov     edi, offset shell_cmd_buf
    mov     dl, 10
    call    utils_itoa
    mov     esi, eax
    call    uart_puts

    # 打印 "KB total, "
    mov     esi, offset meminfo_total_suffix
    call    uart_puts

    # 获取可用内存（KB）
    call    get_free_memory
    push    eax
    mov     edi, offset shell_cmd_buf
    mov     dl, 10
    call    utils_itoa
    mov     esi, eax
    call    uart_puts

    # 打印 "KB free\n"
    mov     esi, offset meminfo_free_suffix
    call    uart_puts
    pop     eax
    pop     eax                 # clean up the first saved eax

    # 打印进程数
    mov     esi, offset meminfo_procs
    call    uart_puts
    call    get_proc_count
    push    eax
    mov     edi, offset shell_cmd_buf
    mov     dl, 10
    call    utils_itoa
    mov     esi, eax
    call    uart_puts
    mov     esi, offset meminfo_procs_suffix
    call    uart_puts
    pop     eax

    pop     ecx
    pop     edi
    pop     esi
    ret

.do_ps:
    mov     esi, offset ps_header
    call    uart_puts

    xor     ebx, ebx            # 进程索引
.ps_loop:
    cmp     ebx, 16
    jge     .ps_done

    mov     eax, ebx
    imul    eax, 256            # PCB_SIZE
    add     eax, offset proc_table

    # 检查进程状态
    mov     esi, [eax]          # PID
    cmp     esi, -1
    je      .ps_next            # 未分配

    # 打印 PID (esi = PID)
    push    esi                 # 保存 PID
    mov     edi, offset shell_cmd_buf
    mov     eax, esi
    mov     dl, 10
    call    utils_itoa
    mov     esi, eax
    call    uart_puts
    pop     esi                 # 恢复 PID

    mov     esi, offset ps_space
    call    uart_puts

    # 状态
    mov     edi, [eax + 4]      # state (注意 eax 已被 utils_itoa 修改)
    # 需要重新计算 PCB 地址
    mov     edi, ebx
    imul    edi, 256
    add     edi, offset proc_table
    mov     ecx, [edi + 4]      # state

    cmp     ecx, 1
    je      .ps_running
    cmp     ecx, 2
    je      .ps_ready
    cmp     ecx, 3
    je      .ps_zombie
    mov     esi, offset ps_dash
    call    uart_puts
    jmp     .ps_state_done

.ps_running:
    mov     esi, offset ps_run_str
    call    uart_puts
    jmp     .ps_state_done

.ps_ready:
    mov     esi, offset ps_ready_str
    call    uart_puts
    jmp     .ps_state_done

.ps_zombie:
    mov     esi, offset ps_zombie_str
    call    uart_puts

.ps_state_done:
    mov     esi, offset ps_space
    call    uart_puts

    # PPID
    mov     edi, ebx
    imul    edi, 256
    add     edi, offset proc_table
    mov     eax, [edi + 76]     # PPID
    mov     edi, offset shell_cmd_buf
    mov     dl, 10
    call    utils_itoa
    mov     esi, eax
    call    uart_puts

    mov     esi, offset ps_newline
    call    uart_puts

.ps_next:
    inc     ebx
    jmp     .ps_loop

.ps_done:
    pop     ecx
    pop     edi
    pop     esi
    ret

.do_wasm:
    # 打印 WASM 模块信息
    call    wasm_print_info
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc
    pop     ecx
    pop     edi
    pop     esi
    ret

.do_wasmrun:
    # wasmrun <filename> - 从VFS加载并执行WASM文件
    # 跳过 "wasmrun " 前缀 (8 字符)
    lea     esi, [shell_cmd_buf + 8]
    call    utils_strlen
    test    eax, eax
    jz      .wasmrun_usage

    # 检查是否是内置 hello.wasm
    lea     edi, [shell_cmd_buf + 8]
    mov     esi, offset cmd_hello_wasm
    call    utils_strcmp
    test    eax, eax
    jz      .wasmrun_hello_builtin

    # 检查是否是内置 calc
    lea     edi, [shell_cmd_buf + 8]
    mov     esi, offset cmd_calc_wasm
    call    utils_strcmp
    test    eax, eax
    jz      .wasmrun_calc_builtin

    # 检查是否是内置 print
    lea     edi, [shell_cmd_buf + 8]
    mov     esi, offset cmd_print_wasm
    call    utils_strcmp
    test    eax, eax
    jz      .wasmrun_print_builtin

    # 尝试从 FAT32 磁盘加载 WASM 文件
    # 获取文件名指针
    lea     esi, [shell_cmd_buf + 8]

    # 将文件名转换为 FAT32 8.3 格式 (存在 fat32_filename_buf)
    call    convert_to_83_format    # 结果在 fat32_filename_buf

    # 使用 fat32_get_file_info 查找文件
    mov     esi, offset fat32_filename_buf
    call    fat32_get_file_info

    # 检查是否找到文件
    cmp     eax, 0xFFFFFFFF
    je      .wasmrun_not_found

    # eax = 簇号, ecx = 文件大小
    push    ecx                    # 保存文件大小

    # 读取文件第一簇到 fat32_file_buffer
    mov     edi, offset fat32_file_buffer
    call    fat32_read_cluster

    # 恢复文件大小
    pop     ecx

    # 检查读取是否成功
    cmp     eax, 0
    jne     .wasmrun_read_err

    # 检查文件大小
    test    ecx, ecx
    jz      .wasmrun_empty

    # 打印加载信息
    push    ecx                   # 保存文件大小
    mov     esi, offset msg_wasmrun_loading
    call    uart_puts
    lea     esi, [shell_cmd_buf + 8]
    call    uart_puts
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc

    # 恢复文件大小
    pop     ecx

    # 解析WASM模块 (从 fat32_file_buffer)
    mov     esi, offset fat32_file_buffer
    call    wasm_parse_module
    test    eax, eax
    jnz     .wasm_parse_err
    call    wasm_load_data

    # 打印解析结果
    call    wasm_print_info
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc

    # 执行函数 0 (main)
    xor     eax, eax
    call    wasm_exec_func

