.do_ls:
    # 列出根目录内容
    mov     ebx, -1               # 根目录
    call    vfs_list_dir
    pop     ecx
    pop     edi
    pop     esi
    ret

.do_cat:
    # 跳过 "cat " 前缀 (4 字符)
    lea     esi, [shell_cmd_buf + 4]
    call    utils_strlen
    test    eax, eax
    jz      .cat_not_found
    # 使用 vfs_find_by_path 支持绝对路径
    lea     esi, [shell_cmd_buf + 4]
    call    vfs_find_by_path
    cmp     eax, -1
    je      .cat_not_found
    call    vfs_read_file
    cmp     ecx, -1
    je      .cat_not_found
    jecxz   .cat_done             # 空文件
.print_content:
    movzx   eax, byte ptr [esi]
    push    ecx
    push    esi
    call    uart_putc
    pop     esi
    pop     ecx
    inc     esi
    dec     ecx
    jnz     .print_content
.cat_done:
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc
    pop     ecx
    pop     edi
    pop     esi
    ret
.cat_not_found:
    # Print the filename that wasn't found
    mov     esi, offset msg_cat_nf_prefix
    call    uart_puts
    lea     esi, [shell_cmd_buf + 4]
    call    uart_puts
    mov     esi, offset msg_cat_nf_suffix
    call    uart_puts
    pop     ecx
    pop     edi
    pop     esi
    ret

.do_touch:
    lea     esi, [shell_cmd_buf + 6]
    call    utils_strlen
    mov     ecx, eax
    cmp     ecx, 0
    je      .touch_usage
    mov     ebx, -1
    call    vfs_create_file_ext
    cmp     eax, -1
    je      .touch_fail
    mov     esi, offset msg_file_created
    call    uart_puts
    mov     esi, offset shell_cmd_buf + 6
    call    uart_puts
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc
    pop     ecx
    pop     edi
    pop     esi
    ret
.touch_usage:
    mov     esi, offset msg_touch_usage
    call    uart_puts
    pop     ecx
    pop     edi
    pop     esi
    ret
.touch_fail:
    mov     esi, offset msg_touch_fail
    call    uart_puts
    pop     ecx
    pop     edi
    pop     esi
    ret

.do_kill:
    # 跳过 "kill " 前缀 (5 字符)
    lea     esi, [shell_cmd_buf + 5]
    call    utils_strlen
    mov     ecx, eax
    cmp     ecx, 0
    je      .kill_usage

    # 解析 PID
    call    utils_atoi
    cmp     eax, 0
    jl      .kill_usage
    cmp     eax, 16
    jge     .kill_usage

    # 通过系统调用终止进程 (SYS_EXIT = 1, ebx = exit_code)
    # 但 SYS_EXIT 只终止当前进程，我们需要通过 INT 0x80 传递 kill 请求
    # 直接使用内核内部接口：设置进程状态为 ZOMBIE
    push    eax                   # 保存请求的 PID
    mov     edi, eax              # pid
    imul    edi, 256
    add     edi, offset proc_table
    mov     eax, [edi]            # 读取 PCB 中的 PID
    cmp     eax, -1
    je      .kill_not_found
    cmp     eax, [esp]            # 与请求的 PID 比较
    jne     .kill_not_found       # PID 不匹配
    mov     dword ptr [edi + 4], 3  # state = PROC_ZOMBIE
    mov     dword ptr [edi + 80], 9  # exit_code = 9 (killed)
    mov     esi, offset msg_kill_ok
    call    uart_puts
    pop     eax
    mov     edi, offset shell_cmd_buf
    mov     dl, 10
    call    utils_itoa
    mov     esi, eax
    call    uart_puts
    mov     esi, offset newline_str2
    call    uart_puts
    pop     ecx
    pop     edi
    pop     esi
    ret

.kill_usage:
    mov     esi, offset msg_kill_usage
    call    uart_puts
    pop     ecx
    pop     edi
    pop     esi
    ret

.kill_not_found:
    pop     eax
    mov     esi, offset msg_kill_notfound
    call    uart_puts
    pop     ecx
    pop     edi
    pop     esi
    ret

.do_date:
    push    ebx
    push    esi
    push    edi

    call    get_tick_count
    # eax = tick count
    push    eax

    mov     esi, offset msg_date_uptime
    call    uart_puts

    pop     eax
    # ticks to seconds (approximate: divide by 100)
    mov     ebx, 100
    xor     edx, edx
    div     ebx
    mov     edi, offset shell_cmd_buf
    mov     dl, 10
    call    utils_itoa
    mov     esi, eax
    call    uart_puts

    mov     esi, offset msg_date_sec_short
    call    uart_puts

    pop     edi
    pop     esi
    pop     ebx
    pop     ecx
    pop     edi
    pop     esi
    ret

.do_echo:
    # 跳过 "echo " 前缀 (5 字符)
    lea     esi, [shell_cmd_buf + 5]
    call    utils_strlen
    mov     ecx, eax
    cmp     ecx, 0
    je      .echo_done

    # 去除首尾双引号
    movzx   eax, byte ptr [esi]
    cmp     al, '"'
    jne     .echo_print
    dec     ecx             # 跳过开头引号
    inc     esi
    movzx   eax, byte ptr [esi + ecx - 1]
    cmp     al, '"'
    jne     .echo_print
    dec     ecx             # 跳过结尾引号

.echo_print:
    test    ecx, ecx
    jz      .echo_done
    # 临时 null 终止以便 uart_puts
    push    esi
    push    ecx
    mov     eax, esi
    add     eax, ecx
    push    eax
    mov     byte ptr [eax], 0
    call    uart_puts
    pop     eax
    pop     ecx
    pop     esi
    push    esi
    push    ecx
    call    vga_print_string_len
    pop     ecx
    pop     esi

.echo_done:
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc
    pop     ecx
    pop     edi
    pop     esi
    ret

# ============================================================================
# shell_parse_ip: Parse dotted-decimal IP address string to 32-bit value
# Input: esi = pointer to string "X.X.X.X"
# Output: eax = IP in network byte order (LE stored as-is), 0 = bad
# ============================================================================
shell_parse_ip:
    push    ebx
    push    ecx
    push    edx
    xor     eax, eax             # result = 0

    # Parse first octet
    call    shell_parse_octet
    cmp     edx, -1
    je      .parse_fail
    mov     ebx, edx             # ebx = octet 1
    mov     dl, [esi]
    cmp     dl, '.'
    jne     .parse_fail
    inc     esi                  # skip '.'

    # Parse second octet
    call    shell_parse_octet
    cmp     edx, -1
    je      .parse_fail
    shl     ebx, 8
    or      ebx, edx             # ebx = octet1.octet2
    mov     dl, [esi]
    cmp     dl, '.'
    jne     .parse_fail
    inc     esi

    # Parse third octet
    call    shell_parse_octet
    cmp     edx, -1
    je      .parse_fail
    shl     ebx, 8
    or      ebx, edx             # ebx = octet1.octet2.octet3
    mov     dl, [esi]
    cmp     dl, '.'
    jne     .parse_fail
    inc     esi

    # Parse fourth octet
    call    shell_parse_octet
    cmp     edx, -1
    je      .parse_fail
    shl     ebx, 8
    or      ebx, edx             # ebx = full IP

    mov     eax, ebx             # return in eax
    pop     edx
    pop     ecx
    pop     ebx
    ret

.parse_fail:
    xor     eax, eax             # return 0 = failure
    pop     edx
    pop     ecx
    pop     ebx
    ret

# shell_parse_octet: Parse decimal number at esi, update esi past digits
# Input: esi = pointer to digits
# Output: edx = value (0-255), -1 on error
shell_parse_octet:
    push    eax
    push    ecx
    xor     edx, edx
    xor     ecx, ecx             # digit count

.parse_oct_loop:
    movzx   eax, byte ptr [esi]
    cmp     al, '0'
    jb      .oct_done
    cmp     al, '9'
    ja      .oct_done
    sub     al, '0'
    imul    edx, edx, 10
    add     edx, eax
    inc     esi
    inc     ecx
    cmp     ecx, 3               # max 3 digits
    jbe     .parse_oct_loop

    cmp     edx, 255
    ja      .oct_fail
    test    ecx, ecx
    jz      .oct_fail
    pop     ecx
    pop     eax
    ret

.oct_fail:
    mov     edx, -1
    pop     ecx
    pop     eax
    ret

.oct_done:
    test    ecx, ecx
    jz      .oct_fail
    cmp     edx, 255
    ja      .oct_fail
    pop     ecx
    pop     eax
    ret

# ============================================================================
# shell_print_ip: Print IP address from 32-bit value
# Input: eax = IP address (little-endian stored)
# ============================================================================
shell_print_ip:
    push    ebx
    push    ecx
    push    edx
    push    esi
    mov     ebx, eax             # save IP
    mov     ecx, 4
.print_octet:
    mov     eax, ebx
    and     eax, 0xFF            # extract one byte
    call    shell_print_dec_byte
    mov     al, '.'
    call    uart_putc
    shr     ebx, 8
    loop    .print_octet
    pop     esi
    pop     edx
    pop     ecx
    pop     ebx
    # Remove trailing dot by overwriting with newline
    ret

# print_ip_inline: Print IP from pointer, no trailing dot
# Input: eax = pointer to 4-byte IP address
print_ip_inline:
    push    eax
    push    ebx
    push    ecx
    push    edx
    mov     ebx, [eax]              # load IP
    mov     ecx, 3
.print_octet2:
    mov     eax, ebx
    and     eax, 0xFF
    call    shell_print_dec_byte
    mov     al, '.'
    call    uart_putc
    shr     ebx, 8
    loop    .print_octet2
    # Last octet without dot
    mov     eax, ebx
    and     eax, 0xFF
    call    shell_print_dec_byte
    pop     edx
    pop     ecx
    pop     ebx
    pop     eax
    ret

# print_ip_arp: Print IP address from value in eax
# Input: eax = IP address (little-endian)
print_ip_arp:
    push    ebx
    push    ecx
    push    edx
    mov     ebx, eax
    mov     ecx, 3
.pia_loop:
    mov     eax, ebx
    and     eax, 0xFF
    call    shell_print_dec_byte
    mov     al, '.'
    call    uart_putc
    shr     ebx, 8
    loop    .pia_loop
    # Last octet without dot
    mov     eax, ebx
    and     eax, 0xFF
    call    shell_print_dec_byte
    pop     edx
    pop     ecx
    pop     ebx
    ret

# print_hex_byte: Print byte in eax as 2 hex chars
# Input: eax = byte value (0-255)
print_hex_byte:
    push    eax
    push    ebx
    mov     ebx, eax
    # High nibble
    mov     eax, ebx
    shr     eax, 4
    cmp     al, 10
    jl      .ph_high_dec
    add     al, 'A' - 10
    jmp     .ph_high_done
.ph_high_dec:
    add     al, '0'
.ph_high_done:
    call    uart_putc
    # Low nibble
    mov     eax, ebx
    and     eax, 0xF
    cmp     al, 10
    jl      .ph_low_dec
    add     al, 'A' - 10
    jmp     .ph_low_done
.ph_low_dec:
    add     al, '0'
.ph_low_done:
    call    uart_putc
    pop     ebx
    pop     eax
    ret

# ============================================================================
# print_i64_result: Print 64-bit return value from wasm_return_value
# Handles both 32-bit (high=0) and full 64-bit values
# ============================================================================
    .globl  print_i64_result
print_i64_result:
    push    eax
    push    edx
    push    esi

    # Read full 64-bit value
    mov     eax, [wasm_return_value]      # low 32 bits
    mov     edx, [wasm_return_value + 4]  # high 32 bits

    # Check if high bits are non-zero (need full 64-bit print)
    test    edx, edx
    jnz     .print_hex64

    # 32-bit value: print as decimal
    mov     edi, offset shell_cmd_buf
    mov     dl, 10
    call    utils_itoa
    mov     esi, eax
    call    uart_puts
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc
    jmp     .print_done

.print_hex64:
    # 64-bit value: print as 0xHHHHHHHHLLLLLLLL
    mov     esi, offset msg_0x
    call    uart_puts
    mov     eax, edx
    call    print_hex8        # print high 32 bits
    mov     eax, [wasm_return_value]
    call    print_hex8        # print low 32 bits
    # print_hex8 already adds newline

.print_done:
    pop     esi
    pop     edx
    pop     eax
    ret

# ============================================================================
# print_f32_result: Print f32 return value as IEEE 754 hex
# Reads 32-bit value from wasm_return_value and prints as 0xXXXXXXXX
# ============================================================================
    .globl  print_f32_result
print_f32_result:
    push    eax
    push    esi

    # Print 0x prefix
    mov     esi, offset msg_0x
    call    uart_puts

    # Read 32-bit value and print as hex
    mov     eax, [wasm_return_value]
    call    print_hex8

    pop     esi
    pop     eax
    ret

# ============================================================================
# print_f64_result: Print f64 return value as IEEE 754 hex
# Reads 64-bit value from wasm_return_value and prints as 0xHHHHHHHHLLLLLLLL
# ============================================================================
    .globl  print_f64_result
print_f64_result:
    push    eax
    push    edx
    push    esi

    # Print 0x prefix
    mov     esi, offset msg_0x
    call    uart_puts

    # Read full 64-bit value and print high 32 bits first
    mov     edx, [wasm_return_value + 4]  # high 32 bits
    mov     eax, edx
    call    print_hex8        # print high 32 bits
    mov     eax, [wasm_return_value]      # low 32 bits
    call    print_hex8        # print low 32 bits

    pop     esi
    pop     edx
    pop     eax
    ret

# shell_parse_dec: Parse decimal number from string at esi
# Input: esi = pointer to digits
# Output: ax = value, esi advanced past digits
shell_parse_dec:
    push    edx
    push    ecx
    xor     edx, edx             # result
    xor     ecx, ecx             # digit count

.parse_loop:
    movzx   eax, byte ptr [esi]
    cmp     al, '0'
    jb      .done_dec
    cmp     al, '9'
    ja      .done_dec
    sub     al, '0'
    imul    edx, edx, 10
    add     edx, eax
    inc     esi
    inc     ecx
    jmp     .parse_loop

.done_dec:
    test    ecx, ecx
    jz      .bad_dec
    mov     ax, dx
    pop     ecx
    pop     edx
    ret

.bad_dec:
    xor     ax, ax
    pop     ecx
    pop     edx
    ret

# shell_print_dec_byte: Print a byte (0-255) as decimal
# Input: eax (low byte = value)
shell_print_dec_byte:
    push    ebx
    push    ecx
    push    edx
    xor     ebx, ebx
    mov     bl, al               # value in ebx

    # Extract hundreds
    xor     ecx, ecx
.print_hundreds:
    cmp     ebx, 100
    jb      .print_tens
    sub     ebx, 100
    inc     ecx
    jmp     .print_hundreds
.print_tens:
    test    ecx, ecx
    jz      .print_tens_loop
    add     ecx, '0'
    mov     al, cl
    call    uart_putc

.print_tens_loop:
    xor     ecx, ecx
.print_tens_again:
    cmp     ebx, 10
    jb      .print_ones
    sub     ebx, 10
    inc     ecx
    jmp     .print_tens_again
.print_ones:
    add     ebx, '0'
    mov     al, bl
    call    uart_putc

    pop     edx
    pop     ecx
    pop     ebx
    ret

# ============================================================================
.do_netpoll:
    mov     esi, offset msg_netpoll_polling
    call    uart_puts
    call    e1000_poll
    test    eax, eax
    jz      .netpoll_none
    mov     esi, offset msg_netpoll_packets
    call    uart_puts
    mov     eax, [e1000_rx_idx]
    call    print_hex8
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc
    jmp     .netpoll_done
.netpoll_none:
    mov     esi, offset msg_netpoll_none
    call    uart_puts
.netpoll_done:
    pop     ecx
    pop     edi
    pop     esi
    ret

.do_ping:
    # Parse IP address from "ping X.X.X.X" (skip "ping " = 5 chars)
    lea     esi, [shell_cmd_buf + 5]
    call    shell_parse_ip
    test    eax, eax
    jz      .ping_bad_ip
    mov     [ping_target_ip], eax

    # Print "Sending ICMP Echo Request to ..."
    mov     esi, offset msg_ping_sending
    call    uart_puts
    mov     eax, [ping_target_ip]
    call    shell_print_ip
    mov     al, 0x0a
    call    uart_putc

    # Set our IP for ARP
    mov     dword ptr [e1000_arp_ip], 0x0F02000A  # 10.0.2.15

    # Send ARP request for target IP
    mov     eax, [ping_target_ip]
    call    e1000_send_arp

    # Build ICMP Echo Request packet in e1000_tx_buf
    # Ethernet header (14 bytes)
    mov     edi, offset e1000_tx_buf

    # Destination MAC: use resolved ARP MAC, or broadcast if ARP failed
    test    eax, eax
    jnz     .ping_use_broadcast
    mov     eax, [e1000_arp_mac]
    mov     [edi], eax
    mov     ax, [e1000_arp_mac + 4]
    mov     [edi + 4], ax
    jmp     .ping_mac_set
.ping_use_broadcast:
    mov     dword ptr [edi], 0xFFFFFFFF
    mov     word ptr [edi + 4], 0xFFFF

.ping_mac_set:
    # Source MAC: our MAC
    mov     eax, [e1000_mac]
    mov     [edi + 6], eax
    mov     ax, [e1000_mac + 4]
    mov     [edi + 10], ax

    # EtherType = IPv4
    mov     word ptr [edi + 12], 0x0800

    # IP header (20 bytes) at offset 14
    mov     edi, offset e1000_tx_buf + 14
    mov     byte ptr [edi], 0x45          # Version=4, IHL=5
    mov     byte ptr [edi + 1], 0         # TOS
    mov     word ptr [edi + 2], 60        # Total length = 20+8+32 = 60
    mov     word ptr [edi + 4], 0x1234    # Identification
    mov     word ptr [edi + 6], 0x4000    # Flags: Don't fragment
    mov     byte ptr [edi + 8], 64        # TTL
    mov     byte ptr [edi + 9], 1         # Protocol = ICMP
    mov     word ptr [edi + 10], 0        # Checksum (to calc)

    # Source IP: 10.0.2.15 (QEMU user net)
    mov     dword ptr [edi + 12], 0x02000A0F  # 10.0.2.15 little-endian... actually host order
    # 10.0.2.15 = 0x0A00020F in network byte order
    # But x86 is little-endian, so store as bytes: 0A 00 02 0F
    mov     dword ptr [edi + 12], 0x0F02000A  # 10.0.2.15 in LE

    # Dest IP: target
    mov     eax, [ping_target_ip]
    mov     [edi + 16], eax

    # Calculate IP checksum
    push    edi
    xor     edx, edx
    mov     ecx, 10             # 10 words
.ip_cksum:
    movzx   eax, word ptr [edi]
    add     edx, eax
    add     edi, 2
    loop    .ip_cksum
.fold_ip:
    mov     eax, edx
    shr     edx, 16
    and     eax, 0xFFFF
    add     eax, edx
    jnc     .ip_fold_done
    add     eax, 1
.ip_fold_done:
    not     ax
    pop     edi
    mov     [edi + 10], ax

    # ICMP header (8 bytes) at offset 34
    mov     edi, offset e1000_tx_buf + 34
    mov     byte ptr [edi], 8         # Type = Echo Request
    mov     byte ptr [edi + 1], 0     # Code
    mov     word ptr [edi + 2], 0     # Checksum (to calc)
    mov     word ptr [edi + 4], 0x0001  # Identifier
    mov     word ptr [edi + 6], 1     # Sequence

    # ICMP payload: 32 bytes of pattern
    mov     edi, offset e1000_tx_buf + 42
    mov     ecx, 8
    mov     eax, 0x01020304
.fill_payload:
    mov     [edi], eax
    add     edi, 4
    add     eax, 0x04040404
    loop    .fill_payload

    # Calculate ICMP checksum (ICMP header + payload = 40 bytes = 20 words)
    mov     edi, offset e1000_tx_buf + 34
    xor     edx, edx
    mov     ecx, 20
.icmp_cksum:
    movzx   eax, word ptr [edi]
    add     edx, eax
    add     edi, 2
    loop    .icmp_cksum
.fold_icmp:
    mov     eax, edx
    shr     edx, 16
    and     eax, 0xFFFF
    add     eax, edx
    jnc     .icmp_fold_done
    add     eax, 1
.icmp_fold_done:
    not     ax
    mov     edi, offset e1000_tx_buf + 36
    mov     [edi], ax

    # Send packet (60 bytes total: 14 eth + 20 IP + 8 ICMP + 32 payload)
    mov     esi, offset e1000_tx_buf
    mov     ecx, 60
    call    e1000_transmit
    test    eax, eax
    jnz     .ping_send_fail

    mov     esi, offset msg_ping_sent
    call    uart_puts
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc

    # Wait a bit for reply, then poll
    mov     ecx, 5000000
.ping_wait:
    dec     ecx
    jnz     .ping_wait

    call    e1000_poll
    test    eax, eax
    jz      .ping_no_reply

    mov     esi, offset msg_ping_reply
    call    uart_puts
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc
    jmp     .ping_done

.ping_no_reply:
    mov     esi, offset msg_ping_noreply
    call    uart_puts
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc
    jmp     .ping_done

.ping_send_fail:
    mov     esi, offset msg_ping_sendfail
    call    uart_puts
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc

.ping_done:
    pop     ecx
    pop     edi
    pop     esi
    ret

.ping_bad_ip:
    mov     esi, offset msg_ping_badip
    call    uart_puts
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc
    pop     ecx
    pop     edi
    pop     esi
    ret

.do_udpsend:
    # Parse "udpsend <ip> <port> <data>"
    lea     esi, [shell_cmd_buf + 8]  # skip "udpsend"

    # Skip space
.skip_space1:
    cmp     byte ptr [esi], ' '
    jne     .udpsend_bad
    inc     esi
    jmp     .skip_space1

    # Parse IP
    call    shell_parse_ip
    test    eax, eax
    jz      .udpsend_bad
    mov     [udp_send_dst_ip_tmp], eax

    # Skip space to port
.skip_space2:
    cmp     byte ptr [esi], ' '
    jne     .parse_port
    inc     esi
    jmp     .skip_space2

    # Parse port number
.parse_port:
    call    shell_parse_dec
    mov     [udp_send_dst_port_tmp], ax

    # Skip space to data
.skip_space3:
    cmp     byte ptr [esi], ' '
    jne     .prep_send
    inc     esi
    jmp     .skip_space3

.prep_send:
    # Our IP for ARP
    mov     dword ptr [e1000_arp_ip], 0x0F02000A  # 10.0.2.15

    # Send ARP for target IP
    mov     eax, [udp_send_dst_ip_tmp]
    call    e1000_send_arp

    # Calculate data length
    mov     edi, esi
    call    utils_strlen
    mov     [udp_send_data_len_tmp], eax   # save length

    # Copy data to send buffer
    mov     edi, offset udp_send_data_buf
    mov     ecx, eax
    push    esi
    push    edi
    shr     ecx, 2
    cld
    rep     movsd
    pop     edi
    pop     esi
    mov     ecx, eax
    and     ecx, 3
    rep     movsb

    # Send UDP packet
    mov     eax, [udp_send_dst_ip_tmp]  # dest IP
    mov     cx, [udp_send_dst_port_tmp]  # dest port
    mov     dx, 5000                     # src port
    mov     esi, offset udp_send_data_buf
    mov     ecx, [udp_send_data_len_tmp]
    call    e1000_send_udp

    mov     esi, offset msg_udpsend_ok
    call    uart_puts
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc

    pop     ecx
    pop     edi
    pop     esi
    ret

.udpsend_bad:
    mov     esi, offset msg_udpsend_bad
    call    uart_puts
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc
    pop     ecx
    pop     edi
    pop     esi
    ret

.do_udprecv:
    # Check if UDP data received
    cmp     dword ptr [udp_recv_ready], 1
    jne     .udprecv_none

    mov     esi, offset msg_udprecv_header
    call    uart_puts

    # Print source IP
    mov     eax, [udp_recv_src_ip]
    call    shell_print_ip
    mov     al, ':'
    call    uart_putc

    # Print source port
    movzx   eax, word ptr [udp_recv_src_port]
    call    shell_print_dec_byte
    mov     esi, offset msg_udprecv_len
    call    uart_puts

    # Print length
    mov     eax, [udp_recv_len]
    call    shell_print_dec_byte

    mov     esi, offset msg_udprecv_data
    call    uart_puts

    # Print data (limit to 64 chars)
    mov     esi, offset udp_recv_buf
    mov     ecx, [udp_recv_len]
    cmp     ecx, 64
    jle     .udprecv_print
    mov     ecx, 64
.udprecv_print:
    mov     edx, ecx
.udprecv_loop:
    test    ecx, ecx
    jz      .udprecv_done
    movzx   eax, byte ptr [esi]
    call    uart_putc
    inc     esi
    dec     ecx
    jmp     .udprecv_loop

.udprecv_done:
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc

    # Clear ready flag
    xor     eax, eax
    mov     [udp_recv_ready], eax
    jmp     .udprecv_exit

.udprecv_none:
    mov     esi, offset msg_udprecv_none
    call    uart_puts
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc

.udprecv_exit:
    pop     ecx
    pop     edi
    pop     esi
    ret

.do_tcpstatus:
    mov     esi, offset msg_tcp_header
    call    uart_puts

    # Print TCP state
    mov     eax, [tcp_state]
    cmp     eax, 0
    je      .tcp_closed
    cmp     eax, 1
    je      .tcp_listen
    cmp     eax, 2
    je      .tcp_synsent
    cmp     eax, 3
    je      .tcp_synrecv
    cmp     eax, 4
    je      .tcp_established

.tcp_closed:
    mov     esi, offset msg_tcp_closed
    call    uart_puts
    jmp     .tcp_state_done
.tcp_listen:
    mov     esi, offset msg_tcp_listen
    call    uart_puts
    jmp     .tcp_state_done
.tcp_synsent:
    mov     esi, offset msg_tcp_synsent
    call    uart_puts
    jmp     .tcp_state_done
.tcp_synrecv:
    mov     esi, offset msg_tcp_synrecv
    call    uart_puts
    jmp     .tcp_state_done
.tcp_established:
    mov     esi, offset msg_tcp_established
    call    uart_puts
.tcp_state_done:
    mov     al, 0x0a
    call    uart_putc

    # Print listen port
    mov     esi, offset msg_tcp_port
    call    uart_puts
    movzx   eax, word ptr [tcp_listen_port]
    call    shell_print_dec_byte
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc

    # Check for received data
    cmp     dword ptr [tcp_recv_ready], 1
    jne     .tcp_no_data

    mov     esi, offset msg_tcp_data
    call    uart_puts
    mov     eax, [tcp_recv_len]
    call    shell_print_dec_byte
    mov     esi, offset msg_tcp_data_len
    call    uart_puts

    # Print data (limit 64)
    mov     esi, offset tcp_recv_buf
    mov     ecx, [tcp_recv_len]
    cmp     ecx, 64
    jle     .tcp_print_data
    mov     ecx, 64
.tcp_print_data:
    test    ecx, ecx
    jz      .tcp_no_data
    movzx   eax, byte ptr [esi]
    call    uart_putc
    inc     esi
    dec     ecx
    jmp     .tcp_print_data

.tcp_no_data:
    pop     ecx
    pop     edi
    pop     esi
    ret

.do_netstat:
    # Print header
    mov     esi, offset msg_netstat_header
    call    uart_puts

    # Print active connection count
    mov     eax, [tcp_conn_active_count]
    mov     esi, offset msg_netstat_active
    call    uart_puts
    call    shell_print_dec_byte
    mov     esi, offset msg_netstat_of
    call    uart_puts
    mov     eax, 4
    call    shell_print_dec_byte
    mov     esi, offset msg_netstat_conns
    call    uart_puts
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc

    # Print connection table header
    mov     esi, offset msg_netstat_tbl_hdr
    call    uart_puts

    # Walk connection table
    xor     ecx, ecx                     # index = 0
    mov     esi, offset tcp_conn_table
.netstat_loop:
    cmp     ecx, 4
    jge     .netstat_done

    # Check if slot is active (state != 0)
    cmp     byte ptr [esi], 0
    je      .netstat_skip

    # Save connection table pointer in ebx
    mov     ebx, esi

    # Print slot index
    mov     eax, ecx
    call    shell_print_dec_byte
    mov     al, ' '
    call    uart_putc

    # Print state name
    movzx   eax, byte ptr [ebx]
    cmp     eax, 1
    je      .net_st_listen
    cmp     eax, 2
    je      .net_st_synsent
    cmp     eax, 3
    je      .net_st_synrecv
    cmp     eax, 4
    je      .net_st_established
    cmp     eax, 5
    je      .net_st_finwait
    cmp     eax, 6
    je      .net_st_closewait
    mov     edi, offset msg_net_st_closed
    jmp     .net_st_print
.net_st_listen:
    mov     edi, offset msg_net_st_listen
    jmp     .net_st_print
.net_st_synsent:
    mov     edi, offset msg_net_st_synsent
    jmp     .net_st_print
.net_st_synrecv:
    mov     edi, offset msg_net_st_synrecv
    jmp     .net_st_print
.net_st_established:
    mov     edi, offset msg_net_st_established
    jmp     .net_st_print
.net_st_finwait:
    mov     edi, offset msg_net_st_finwait
    jmp     .net_st_print
.net_st_closewait:
    mov     edi, offset msg_net_st_closewait
    jmp     .net_st_print

.net_st_print:
    mov     esi, edi
    call    uart_puts

    # Pad with spaces
    mov     al, ' '
    call    uart_putc
    call    uart_putc

    # Print remote IP (from connection entry at ebx+4)
    mov     eax, [ebx + 4]
    call    print_ip_inline

    # Print colon and remote port (from connection entry at ebx+8)
    mov     al, ':'
    call    uart_putc
    movzx   eax, word ptr [ebx + 8]
    call    shell_print_dec_byte

    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc

    # Restore esi from ebx for next iteration
    mov     esi, ebx
    jmp     .netstat_next

.netstat_skip:
    # Save esi, print empty slot, restore esi
    push    esi
    mov     eax, ecx
    call    shell_print_dec_byte
    mov     esi, offset msg_net_st_empty
    call    uart_puts
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc
    pop     esi

.netstat_next:
    add     esi, 24                     # next entry
    inc     ecx
    jmp     .netstat_loop

.netstat_done:
    ret

.do_arp:
    # Print header
    mov     esi, offset msg_arp_header
    call    uart_puts

    # Print ARP cache size
    mov     eax, [e1000_arp_cache_size]
    mov     esi, offset msg_arp_entries
    call    uart_puts
    call    shell_print_dec_byte
    mov     esi, offset msg_arp_of
    call    uart_puts
    mov     eax, 8
    call    shell_print_dec_byte
    mov     esi, offset msg_arp_entries2
    call    uart_puts
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc

    # Print table header
    mov     esi, offset msg_arp_tbl_hdr
    call    uart_puts

    # Walk ARP cache
    xor     ecx, ecx                     # index = 0
    mov     esi, offset e1000_arp_cache
.arp_loop:
    cmp     ecx, 8
    jge     .arp_done

    # Check if slot is active (IP != 0)
    cmp     dword ptr [esi], 0
    je      .arp_skip

    # Print slot index
    mov     eax, ecx
    call    shell_print_dec_byte
    mov     al, ' '
    call    uart_putc

    # Print IP address
    mov     eax, [esi]
    call    print_ip_arp

    # Pad
    mov     al, ' '
    call    uart_putc
    mov     al, ' '
    call    uart_putc

    # Print MAC address
    movzx   eax, byte ptr [esi + 4]
    call    print_hex_byte
    mov     al, ':'
    call    uart_putc
    movzx   eax, byte ptr [esi + 5]
    call    print_hex_byte
    mov     al, ':'
    call    uart_putc
    movzx   eax, byte ptr [esi + 6]
    call    print_hex_byte
    mov     al, ':'
    call    uart_putc
    movzx   eax, byte ptr [esi + 7]
    call    print_hex_byte
    mov     al, ':'
    call    uart_putc
    movzx   eax, byte ptr [esi + 8]
    call    print_hex_byte
    mov     al, ':'
    call    uart_putc
    movzx   eax, byte ptr [esi + 9]
    call    print_hex_byte
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc
    jmp     .arp_next

.arp_skip:
    # Print empty slot (save esi first)
    push    esi
    mov     eax, ecx
    call    shell_print_dec_byte
    mov     esi, offset msg_arp_empty
    call    uart_puts
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc
    pop     esi

.arp_next:
    add     esi, 12                     # next entry
    inc     ecx
    jmp     .arp_loop

.arp_done:
    ret

.do_httpserver:
    # Check for "on" or "off" argument after "httpserver" (10 chars)
    lea     esi, [shell_cmd_buf + 10]
    lodsb
    test    al, al
    jz      .http_show_status
    cmp     al, ' '
    je      .http_check_args
    jmp     .http_done

.http_check_args:
    # Skip spaces
    lodsb
    cmp     al, ' '
    je      .http_check_args
    cmp     al, 0
    je      .http_show_status
    dec     esi

    # Check if "on"
    cmp     byte ptr [esi], 'o'
    jne     .http_check_off
    cmp     byte ptr [esi + 1], 'n'
    jne     .http_check_off
    mov     dword ptr [tcp_http_enabled], 1
    mov     esi, offset msg_http_on
    call    uart_puts
    jmp     .http_done

.http_check_off:
    # Check if "off"
    cmp     byte ptr [esi], 'o'
    jne     .http_show_status
    cmp     byte ptr [esi + 1], 'f'
    jne     .http_show_status
    cmp     byte ptr [esi + 2], 'f'
    jne     .http_show_status
    mov     dword ptr [tcp_http_enabled], 0
    mov     esi, offset msg_http_off
    call    uart_puts
    jmp     .http_done

.http_show_status:
    cmp     dword ptr [tcp_http_enabled], 0
    je      .http_is_off
    mov     esi, offset msg_http_enabled
    call    uart_puts
    jmp     .http_done
.http_is_off:
    mov     esi, offset msg_http_disabled
    call    uart_puts

.http_done:
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc

    # Print connection stats
    mov     esi, offset msg_tcp_conn_count
    call    uart_puts
    mov     eax, [tcp_conn_count]
    call    shell_print_dec_byte
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc

    # Print RST received
    cmp     dword ptr [tcp_rst_received], 0
    je      .http_no_rst
    mov     esi, offset msg_tcp_rst_recv
    call    uart_puts
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc
.http_no_rst:

    # Print FIN received
    cmp     dword ptr [tcp_fin_received], 0
    je      .http_no_fin
    mov     esi, offset msg_tcp_fin_recv
    call    uart_puts
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc
.http_no_fin:

    pop     ecx
    pop     edi
    pop     esi
    ret

.do_netinit:
    mov     esi, offset msg_netinit_start
    call    uart_puts
    call    virtio_net_init
    test    eax, eax
    jnz     .netinit_fail
    mov     esi, offset msg_netinit_ok
    call    uart_puts
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc
    pop     ecx
    pop     edi
    pop     esi
    ret

.netinit_fail:
    mov     esi, offset msg_netinit_fail
    call    uart_puts
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc
    pop     ecx
    pop     edi
    pop     esi
    ret

.do_netinfo:
    # 检查网络状态
    mov     eax, [virtio_net_status]
    test    eax, eax
    jz      .netinfo_not_found

    # 打印网络信息标题
    mov     esi, offset msg_netinfo_header
    call    uart_puts

    # 打印MAC地址
    mov     esi, offset msg_netinfo_mac
    call    uart_puts

    call    virtio_net_get_mac
    mov     ecx, 6
    mov     ebx, esi
.netinfo_mac_loop:
    movzx   eax, byte ptr [ebx]
    push    ebx
    push    ecx
    mov     edi, offset shell_cmd_buf
    mov     dl, 16
    call    utils_itoa
    mov     esi, eax
    call    uart_puts
    pop     ecx
    pop     ebx
    inc     ebx
    dec     ecx
    jz      .netinfo_mac_done
    mov     al, ':'
    call    uart_putc
    jmp     .netinfo_mac_loop

.netinfo_mac_done:
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc

    # 打印IRQ线号
    mov     esi, offset msg_netinfo_irq
    call    uart_puts
    mov     eax, [virtio_irq_line]
    push    eax
    mov     edi, offset shell_cmd_buf
    mov     dl, 10
    call    utils_itoa
    mov     esi, eax
    call    uart_puts
    pop     eax
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc

    pop     ecx
    pop     edi
    pop     esi
    ret

.netinfo_not_found:
    mov     esi, offset msg_netinfo_none
    call    uart_puts
    pop     ecx
    pop     edi
    pop     esi
    ret

.do_dhcp:
    # Run DHCP client: send Discover and wait for Offer/ACK
    call    e1000_send_dhcp_discover

    # Poll for DHCP responses (~5 seconds)
    mov     ecx, 50
.dhcp_poll_loop:
    call    e1000_poll_delay
    cmp     dword ptr [e1000_dhcp_state], 3  # bound
    je      .dhcp_bound
    cmp     dword ptr [e1000_dhcp_state], 2  # got_offer
    je      .dhcp_send_request
    dec     ecx
    jnz     .dhcp_poll_loop
    jmp     .dhcp_timeout

.dhcp_send_request:
    # Got offer, now send DHCP Request
    call    e1000_send_dhcp_request
    mov     ecx, 30
.dhcp_poll2:
    call    e1000_poll_delay
    cmp     dword ptr [e1000_dhcp_state], 3  # bound
    je      .dhcp_bound
    dec     ecx
    jnz     .dhcp_poll2
    jmp     .dhcp_timeout

.dhcp_bound:
    # Print our assigned IP
    mov     esi, offset msg_dhcp_bound
    call    uart_puts
    mov     eax, [e1000_our_ip]
    call    shell_print_ip
    mov     al, 0x0a
    call    uart_putc

    # Print gateway
    mov     esi, offset msg_dhcp_gw
    call    uart_puts
    mov     eax, [e1000_gateway_ip]
    call    shell_print_ip
    mov     al, 0x0a
    call    uart_putc
    jmp     .dhcp_done

.dhcp_timeout:
    mov     esi, offset msg_dhcp_timeout
    call    uart_puts

.dhcp_done:
    ret

.do_pciscan:
    # 扫描 PCI 设备并显示 vendor/device ID
    # 使用 BSS 变量存储计数器，避免寄存器冲突
    push    ebp
    mov     ebp, esp

    # 初始化计数器
    mov     dword ptr [pciscan_bus], 0
    mov     dword ptr [pciscan_count], 0

.pciscan_bus_loop:
    mov     dword ptr [pciscan_dev], 0

.pciscan_dev_loop:
    mov     dword ptr [pciscan_func], 0

.pciscan_func_loop:
    # 读取 Vendor ID (offset 0)
    mov     eax, [pciscan_bus]    # bus
    mov     edx, [pciscan_dev]    # device
    mov     ecx, [pciscan_func]   # function
    mov     ebx, 0                # offset
    call    pci_read_config

    # 检查设备是否存在
    and     eax, 0xFFFF
    cmp     ax, 0xFFFF
    je      .pciscan_next_func

    # 找到设备，打印信息
    push    eax                   # 保存 vendor ID

    # 打印 "PCI: B:D:F"
    mov     esi, offset msg_pci_device
    call    uart_puts

    # 打印 bus
    mov     eax, [pciscan_bus]
    mov     edi, offset shell_cmd_buf
    mov     dl, 16
    call    utils_itoa
    mov     esi, eax
    call    uart_puts

    mov     al, ':'
    call    uart_putc

    # 打印 device
    mov     eax, [pciscan_dev]
    mov     edi, offset shell_cmd_buf
    mov     dl, 16
    call    utils_itoa
    mov     esi, eax
    call    uart_puts

    mov     al, ':'
    call    uart_putc

    # 打印 function
    mov     eax, [pciscan_func]
    mov     edi, offset shell_cmd_buf
    mov     dl, 16
    call    utils_itoa
    mov     esi, eax
    call    uart_puts

    # 打印 Vendor ID
    mov     esi, offset msg_pci_vendor
    call    uart_puts

    pop     eax                   # 恢复 vendor ID
    mov     edi, offset shell_cmd_buf
    mov     dl, 16
    call    utils_itoa
    mov     esi, eax
    call    uart_puts

    # 打印 Device ID
    mov     esi, offset msg_pci_device_id
    call    uart_puts

    # 重新读取 Device ID
    mov     eax, [pciscan_bus]
    mov     edx, [pciscan_dev]
    mov     ecx, [pciscan_func]
    mov     ebx, 2                # offset for Device ID
    call    pci_read_config

    shr     eax, 16
    and     eax, 0xFFFF
    mov     edi, offset shell_cmd_buf
    mov     dl, 16
    call    utils_itoa
    mov     esi, eax
    call    uart_puts

    # 换行
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc

    # 设备计数
    inc     dword ptr [pciscan_count]

.pciscan_next_func:
    inc     dword ptr [pciscan_func]
    mov     ecx, [pciscan_func]
    cmp     ecx, 8
    jl      .pciscan_func_loop

.pciscan_next_dev:
    inc     dword ptr [pciscan_dev]
    mov     edx, [pciscan_dev]
    cmp     edx, 32
    jl      .pciscan_dev_loop

.pciscan_next_bus:
    inc     dword ptr [pciscan_bus]
    mov     ebx, [pciscan_bus]
    cmp     ebx, 256
    jl      .pciscan_bus_loop

    # 检查是否找到设备
    mov     eax, [pciscan_count]
    test    eax, eax
    jnz     .pciscan_done
    mov     esi, offset msg_pci_none
    call    uart_puts

.pciscan_done:
    pop     ebp
    pop     ecx
    pop     edi
    pop     esi
    ret

# ============================================================================
# .do_ring3: 进入用户模式 (ring 3)
# ============================================================================
.do_ring3:
    # 打印进入消息
    mov     esi, offset msg_ring3_entering
    call    uart_puts

    # 调用 enter_ring3 进入用户模式
    call    enter_ring3

    # 如果从 ring3 返回（不应该发生）
    mov     esi, offset msg_ring3_returned
    call    uart_puts

    pop     ecx
    pop     edi
    pop     esi
    ret

# ============================================================================
# .do_diskinfo: 显示磁盘信息
# ============================================================================
.do_diskinfo:
    # 打印磁盘信息标题
    mov     esi, offset msg_diskinfo_header
    call    uart_puts

    # 获取 ATA 状态
    call    ata_get_status
    movzx   eax, al              # 扩展到 32-bit
    mov     esi, offset msg_disk_status
    call    uart_puts
    mov     edi, offset msg_diskread_hex  # 使用 hex buffer
    mov     dl, 16
    call    utils_itoa
    mov     esi, eax
    call    uart_puts
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc

    # 打印 LBA 支持
    mov     esi, offset msg_disk_lba
    call    uart_puts

    # 打印完成
    mov     esi, offset msg_disk_ok
    call    uart_puts

    pop     ecx
    pop     edi
    pop     esi
    ret

# ============================================================================
# .do_fatls: 列出 FAT32 根目录文件
# ============================================================================
.do_fatls:
    # 打印 FAT32 根目录标题
    mov     esi, offset msg_fatls_header
    call    uart_puts

    # 调用 FAT32 列根目录函数
    call    fat32_list_root

    # 检查结果
    cmp     eax, 0xFFFFFFFF
    je      .fatls_fail

    # 打印文件数量
    push    eax
    mov     esi, offset msg_fatls_count
    call    uart_puts
    pop     eax
    mov     edi, offset shell_cmd_buf
    mov     dl, 10
    call    utils_itoa
    mov     esi, eax
    call    uart_puts
    mov     al, 0x0D
    call    uart_putc
    mov     al, 0x0A
    call    uart_putc

    pop     ecx
    pop     edi
    pop     esi
    ret

.fatls_fail:
    mov     esi, offset msg_fatls_fail
    call    uart_puts
    pop     ecx
    pop     edi
    pop     esi
    ret

# ============================================================================
# .do_fatread: 读取 FAT32 文件
# ============================================================================
.do_fatread:
    # 获取文件名参数 (从 shell_cmd_buf + 8 开始)
    mov     esi, offset shell_cmd_buf
    add     esi, 8                 # 跳过 "fatread "

    # 检查是否有参数
    mov     al, [esi]
    test    al, al
    jz      .fatread_usage

    # 保存文件名指针
    push    esi

    # 打印读取消息
    mov     esi, offset msg_fatread_reading
    call    uart_puts

    # 恢复文件名指针并转换为 8.3 格式
    pop     esi

    # 将文件名转换为 FAT32 8.3 格式 (存在 fat32_filename_buf)
    # esi = 输入文件名
    call    convert_to_83_format    # 结果在 fat32_filename_buf

    # 使用 fat32_get_file_info 查找文件
    mov     esi, offset fat32_filename_buf
    call    fat32_get_file_info

    # 检查是否找到文件
    cmp     eax, 0xFFFFFFFF
    je      .fatread_not_found

    # eax = 簇号, ecx = 文件大小
    push    ecx                    # 保存文件大小

    # 读取文件第一簇
    mov     edi, offset fat32_file_buffer
    call    fat32_read_cluster

    # 恢复文件大小
    pop     ecx

    # 检查读取是否成功
    cmp     eax, 0
    jne     .fatread_read_fail

    # 打印文件内容 (最多显示 min(文件大小, 512))
    cmp     ecx, 512
    jbe     .fatread_print
    mov     ecx, 512

.fatread_print:
    mov     esi, offset fat32_file_buffer
.fatread_print_loop:
    test    ecx, ecx
    jz      .fatread_done
    movzx   eax, byte ptr [esi]
    cmp     al, 0x0D              # 跳过 CR
    je      .fatread_print_skip
    cmp     al, 0x0A              # 保留 LF
    je      .fatread_print_lf
    cmp     al, 0x20
    jb      .fatread_print_skip   # 跳过其他控制字符
    call    uart_putc
    jmp     .fatread_print_next
.fatread_print_lf:
    mov     al, 0x0D
    call    uart_putc
    mov     al, 0x0A
    call    uart_putc
    jmp     .fatread_print_next
.fatread_print_skip:
.fatread_print_next:
    inc     esi
    dec     ecx
    jmp     .fatread_print_loop

.fatread_done:
    # 打印换行
    mov     al, 0x0D
    call    uart_putc
    mov     al, 0x0A
    call    uart_putc
    pop     ecx
    pop     edi
    pop     esi
    ret

.fatread_usage:
    mov     esi, offset msg_fatread_usage
    call    uart_puts
    pop     ecx
    pop     edi
    pop     esi
    ret

.fatread_not_found:
    mov     esi, offset msg_fatread_not_found
    call    uart_puts
    pop     ecx
    pop     edi
    pop     esi
    ret

.fatread_read_fail:
    mov     esi, offset msg_fatread_fail
    call    uart_puts
    pop     ecx
    pop     edi
    pop     esi
    ret

# ============================================================================
# convert_to_83_format: 将文件名转换为 FAT32 8.3 格式
# 输入: esi = 文件名指针 (如 "HELLO.TXT")
# 输出: fat32_filename_buf = 11 字符 (如 "HELLO    TXT")
# ============================================================================
convert_to_83_format:
    push    eax
    push    ecx
    push    edi

    mov     edi, offset fat32_filename_buf

    # 初始化为空格
    mov     ecx, 11
    mov     al, ' '
    cld
    rep     stosb

    # 重置目标指针
    mov     edi, offset fat32_filename_buf
    mov     ecx, 0                 # 字符计数

.cvt_loop:
    movzx   eax, byte ptr [esi]
    test    al, al
    jz      .cvt_done              # 字符串结束

    # 检查扩展名分隔符
    cmp     al, '.'
    je      .cvt_ext

    # 转换为大写
    cmp     al, 'a'
    jb      .cvt_store
    cmp     al, 'z'
    ja      .cvt_store
    sub     al, 32                 # 转大写

.cvt_store:
    # 存储字符
    cmp     ecx, 8
    jge     .cvt_next              # 文件名部分已满
    mov     [edi + ecx], al

.cvt_next:
    inc     ecx
    inc     esi
    jmp     .cvt_loop

.cvt_ext:
    # 跳转到扩展名位置 (位置 8)
    mov     ecx, 8
    inc     esi
    jmp     .cvt_loop

.cvt_done:
    pop     edi
    pop     ecx
    pop     eax
    ret

# ============================================================================
# .do_diskread: 读取磁盘扇区
# ============================================================================
.do_diskread:
    # 解析 LBA 参数 (从 shell_cmd_buf + 9 开始)
    mov     esi, offset shell_cmd_buf
    add     esi, 9               # 跳过 "diskread "

    # 检查是否有参数
    mov     al, [esi]
    test    al, al
    jz      .diskread_usage

    # 解析十六进制 LBA
    call    utils_parse_hex     # eax = LBA value

    # 打印读取信息
    push    eax                 # 保存 LBA
    mov     esi, offset msg_diskread_header
    call    uart_puts
    mov     esi, offset msg_diskread_lba
    call    uart_puts
    pop     eax
    push    eax                 # 再次保存 LBA
    mov     edi, offset msg_diskread_hex  # buffer for hex output
    mov     dl, 16
    call    utils_itoa
    mov     esi, eax            # utils_itoa 返回 buffer pointer
    call    uart_puts
    mov     esi, offset msg_diskread_done
    call    uart_puts

    # 读取扇区到 ata_buffer
    pop     eax                 # LBA
    push    offset ata_buffer   # 缓冲区指针作为参数
    push    eax                 # 保存 LBA for later cleanup
    mov     edi, offset ata_buffer
    call    ata_read_sector
    pop     eax                 # 恢复 LBA (清理栈)
    add     esp, 4              # 清理缓冲区参数
    test    eax, eax
    jnz     .diskread_fail

    # 打印 hexdump (前 16 字节)
    mov     esi, offset msg_diskread_data
    call    uart_puts

    mov     esi, offset ata_buffer
    mov     ecx, 16
    cld
.hexdump_loop:
    lodsb
    push    ecx
    push    esi
    mov     esi, offset msg_diskread_hex
    call    utils_itoa_single   # convert al to hex string
    mov     esi, offset msg_diskread_hex
    call    uart_puts
    mov     al, ' '
    call    uart_putc
    pop     esi
    pop     ecx
    dec     ecx
    jnz     .hexdump_loop

    # 换行
    mov     al, 0x0a
    call    uart_putc
    mov     al, 0x0d
    call    uart_putc

    pop     ecx
    pop     edi
    pop     esi
    ret

.diskread_fail:
    mov     esi, offset msg_diskread_fail
    call    uart_puts
    pop     eax
    pop     ecx
    pop     edi
    pop     esi
    ret

.diskread_usage:
    mov     esi, offset msg_diskread_usage
    call    uart_puts
    pop     ecx
    pop     edi
    pop     esi
    ret

# ============================================================================
# .do_diskwrite: 写入磁盘扇区
# ============================================================================
.do_diskwrite:
    # 解析 LBA 参数 (从 shell_cmd_buf + 10 开始)
    mov     esi, offset shell_cmd_buf
    add     esi, 10              # 跳过 "diskwrite "

    # 检查是否有参数
    mov     al, [esi]
    test    al, al
    jz      .diskwrite_usage

    # 解析十六进制 LBA
    call    utils_parse_hex     # eax = LBA value

    # 打印写入信息
    push    eax                 # 保存 LBA
    mov     esi, offset msg_diskwrite_header
    call    uart_puts
    mov     esi, offset msg_diskwrite_lba
    call    uart_puts
    pop     eax
    push    eax                 # 再次保存 LBA
    mov     edi, offset msg_diskread_hex  # 使用 hex buffer
    mov     dl, 16
    call    utils_itoa
    mov     esi, eax            # utils_itoa 返回 buffer pointer
    call    uart_puts

    # 准备测试数据 - 填充 ata_buffer
    mov     edi, offset ata_buffer
    mov     ecx, 512
    mov     al, 'A'
.fill_buffer:
    mov     [edi], al
    inc     edi
    dec     ecx
    jnz     .fill_buffer

    # 写入特定标记 "AIASM_V101_WRITE_TEST"
    mov     edi, offset ata_buffer
    mov     byte ptr [edi], 'A'
    mov     byte ptr [edi + 1], 'I'
    mov     byte ptr [edi + 2], 'A'
    mov     byte ptr [edi + 3], 'S'
    mov     byte ptr [edi + 4], 'M'
    mov     byte ptr [edi + 5], '_'
    mov     byte ptr [edi + 6], 'V'
    mov     byte ptr [edi + 7], '1'
    mov     byte ptr [edi + 8], '.'
    mov     byte ptr [edi + 9], '0'
    mov     byte ptr [edi + 10], '1'
    mov     byte ptr [edi + 11], '_'
    mov     byte ptr [edi + 12], 'W'
    mov     byte ptr [edi + 13], 'R'
    mov     byte ptr [edi + 14], 'I'
    mov     byte ptr [edi + 15], 'T'
    mov     byte ptr [edi + 16], 'E'
    mov     byte ptr [edi + 17], '_'
    mov     byte ptr [edi + 18], 'T'
    mov     byte ptr [edi + 19], 'E'
    mov     byte ptr [edi + 20], 'S'
    mov     byte ptr [edi + 21], 'T'
    mov     byte ptr [edi + 22], 0

    # 写入扇区
    pop     eax                 # LBA
    push    offset ata_buffer   # 缓冲区指针作为参数
    push    eax                 # 保存 LBA for later cleanup
    mov     edi, offset ata_buffer
    call    ata_write_sector
    pop     eax                 # 恢复 LBA (清理栈)
    add     esp, 4              # 清理缓冲区参数
    test    eax, eax
    jnz     .diskwrite_fail

    # 打印成功消息
    mov     esi, offset msg_diskwrite_done
    call    uart_puts
    mov     esi, offset msg_diskwrite_testdata
    call    uart_puts

    pop     ecx
    pop     edi
    pop     esi
    ret

.diskwrite_fail:
    mov     esi, offset msg_diskwrite_fail
    call    uart_puts
    pop     eax
    pop     ecx
    pop     edi
    pop     esi
    ret

.diskwrite_usage:
    mov     esi, offset msg_diskwrite_usage
    call    uart_puts
    pop     ecx
    pop     edi
    pop     esi
    ret

